void require(bool condition, const std::string& message)
{
    if (!condition) {
        throw std::runtime_error(message);
    }
}

bool intersectsAvailableScreen(const QWidget& window)
{
    const QList<QScreen*> screens = QGuiApplication::screens();
    if (screens.empty()) {
        return true;
    }
    for (QScreen* screen : screens) {
        if (screen != nullptr && screen->availableGeometry().intersects(window.frameGeometry())) {
            return true;
        }
    }
    return false;
}

int visibleAreaOnAvailableScreens(const QWidget& window)
{
    int area = 0;
    const QRect frame = window.frameGeometry();
    for (QScreen* screen : QGuiApplication::screens()) {
        if (screen == nullptr) {
            continue;
        }
        const QRect visible = screen->availableGeometry().intersected(frame);
        if (visible.isValid()) {
            area += visible.width() * visible.height();
        }
    }
    return area;
}

bool hasSubstantialVisibleArea(const QWidget& window)
{
    if (QGuiApplication::screens().empty()) {
        return true;
    }
    const QRect frame = window.frameGeometry();
    const int requiredWidth = std::min(std::max(frame.width(), 1), 320);
    const int requiredHeight = std::min(std::max(frame.height(), 1), 240);
    return visibleAreaOnAvailableScreens(window) >= requiredWidth * requiredHeight;
}

int countOccurrences(const QString& text, const QString& needle)
{
    int count = 0;
    qsizetype position = 0;
    while ((position = text.indexOf(needle, position)) >= 0) {
        ++count;
        position += needle.size();
    }
    return count;
}

QColor renderedWidgetPixel(QWidget& widget, QPoint point)
{
    const QSize size(
        std::max(widget.width(), point.x() + 1),
        std::max(widget.height(), point.y() + 1));
    QImage image(size, QImage::Format_ARGB32_Premultiplied);
    image.fill(Qt::transparent);
    widget.render(&image);
    return image.pixelColor(point);
}

int countNonTransparentPixels(const QImage& image)
{
    int count = 0;
    for (int y = 0; y < image.height(); ++y) {
        for (int x = 0; x < image.width(); ++x) {
            if (image.pixelColor(x, y).alpha() > 0) {
                ++count;
            }
        }
    }
    return count;
}

QImage renderWidget(QWidget& widget)
{
    const QSize size(std::max(widget.width(), 1), std::max(widget.height(), 1));
    QImage image(size, QImage::Format_ARGB32_Premultiplied);
    image.fill(Qt::transparent);
    widget.render(&image);
    return image;
}

void requireUsableWidgetGeometry(const QWidget* widget, int minWidth, int minHeight, const char* message)
{
    require(widget != nullptr, message);
    const QSize size = widget->size();
    require(
        size.width() >= minWidth && size.height() >= minHeight,
        std::string(message) + "; got " + std::to_string(size.width()) + "x" + std::to_string(size.height()));
}

void requireToolbarActionGeometriesDoNotOverlap(const QToolBar* toolbar)
{
    require(toolbar != nullptr, "toolbar geometry check requires a toolbar");
    std::vector<QRect> commandGeometries;
    for (QAction* action : toolbar->actions()) {
        if (action == nullptr || action->isSeparator() || !action->isVisible()) {
            continue;
        }
        const QRect geometry = toolbar->actionGeometry(action);
        require(
            geometry.width() > 0 && geometry.height() > 0,
            "visible toolbar command actions should have non-empty geometry");
        for (const QRect& previous : commandGeometries) {
            require(
                !geometry.intersects(previous),
                "visible toolbar command action geometries should not overlap");
        }
        commandGeometries.push_back(geometry);
    }
    require(commandGeometries.size() == 8, "main toolbar should expose eight visible command geometries");
}

bool isDarkGraphBackground(const QColor& color)
{
    return color.red() < 50 && color.green() < 55 && color.blue() < 65;
}

bool isLightGraphBackground(const QColor& color)
{
    return color.red() > 230 && color.green() > 230 && color.blue() > 230;
}

int visibleProgressDialogCount()
{
    int count = 0;
    for (QWidget* widget : QApplication::topLevelWidgets()) {
        auto* progress = qobject_cast<QProgressDialog*>(widget);
        if (progress != nullptr && progress->isVisible()) {
            ++count;
        }
    }
    return count;
}

QAction* findActionByText(QWidget& window, const QString& text)
{
    for (QAction* action : window.findChildren<QAction*>()) {
        if (action->text() == text) {
            return action;
        }
    }
    return nullptr;
}

QTableWidget* findTableWithHeader(QWidget& window, const QString& header)
{
    for (QTableWidget* table : window.findChildren<QTableWidget*>()) {
        for (int column = 0; column < table->columnCount(); ++column) {
            const QTableWidgetItem* item = table->horizontalHeaderItem(column);
            if (item != nullptr && item->text() == header) {
                return table;
            }
        }
    }
    return nullptr;
}

QString tableText(QTableWidget* table, int row, int column)
{
    if (table == nullptr) {
        return {};
    }
    QTableWidgetItem* item = table->item(row, column);
    return item == nullptr ? QString() : item->text();
}

void settleEvents(int milliseconds = 20)
{
    QEventLoop loop;
    QTimer::singleShot(milliseconds, &loop, &QEventLoop::quit);
    loop.exec(QEventLoop::AllEvents);
}

template <typename TimeoutHandler>
void execLoopWithTimeout(QEventLoop& loop, int milliseconds, TimeoutHandler timeoutHandler)
{
    QTimer timeout;
    timeout.setSingleShot(true);
    QObject::connect(&timeout, &QTimer::timeout, &loop, [&] {
        timeoutHandler();
        loop.quit();
    });
    timeout.start(milliseconds);
    loop.exec();
    timeout.stop();
}

void execLoopWithTimeout(QEventLoop& loop, int milliseconds)
{
    execLoopWithTimeout(loop, milliseconds, [] {});
}

void rejectTopLevelDialogs()
{
    QList<QDialog*> dialogs;
    for (QWidget* widget : QApplication::topLevelWidgets()) {
        if (auto* dialog = qobject_cast<QDialog*>(widget)) {
            dialogs.push_back(dialog);
        }
    }
    for (QDialog* dialog : dialogs) {
        if (dialog != nullptr) {
            dialog->reject();
        }
    }
}

bool acceptMessageBoxContaining(const QString& needle)
{
    for (QWidget* widget : QApplication::topLevelWidgets()) {
        auto* messageBox = qobject_cast<QMessageBox*>(widget);
        if (messageBox == nullptr) {
            continue;
        }
        const QString text =
            messageBox->windowTitle() + "\n" + messageBox->text() + "\n" +
            messageBox->informativeText() + "\n" + messageBox->detailedText();
        if (!text.contains(needle)) {
            continue;
        }
        if (auto* okButton = messageBox->button(QMessageBox::Ok)) {
            okButton->click();
        } else {
            messageBox->accept();
        }
        return true;
    }
    return false;
}

bool setFormLineEdit(QDialog* dialog, const QString& labelText, const QString& value)
{
    if (dialog == nullptr) {
        return false;
    }
    const QString i18nKey = labelText;
    for (QFormLayout* form : dialog->findChildren<QFormLayout*>()) {
        for (int row = 0; row < form->rowCount(); ++row) {
            QLayoutItem* labelItem = form->itemAt(row, QFormLayout::LabelRole);
            QLayoutItem* fieldItem = form->itemAt(row, QFormLayout::FieldRole);
            auto* label = labelItem == nullptr ? nullptr : qobject_cast<QLabel*>(labelItem->widget());
            QWidget* field = fieldItem == nullptr ? nullptr : fieldItem->widget();
            const QString key = label == nullptr
                ? QString()
                : label->property("lizzieSettingsI18nKey").toString();
            if (label == nullptr || field == nullptr || (label->text() != labelText && key != i18nKey)) {
                continue;
            }
            auto* edit = qobject_cast<QLineEdit*>(field);
            if (edit == nullptr) {
                edit = field->findChild<QLineEdit*>();
            }
            if (edit == nullptr) {
                return false;
            }
            edit->setText(value);
            return true;
        }
    }
    return false;
}

