bool setFormComboBox(QDialog* dialog, const QString& labelText, const QString& value)
{
    if (dialog == nullptr) {
        return false;
    }
    const QString i18nKey = labelText;
    for (QFormLayout* form : dialog->findChildren<QFormLayout*>()) {
        for (int row = 0; row < form->rowCount(); ++row) {
            QLayoutItem* labelItem = form->itemAt(row, QFormLayout::LabelRole);
            QLayoutItem* fieldItem = form->itemAt(row, QFormLayout::FieldRole);
            auto* label = labelItem == nullptr ? nullptr : qobject_cast<QLabel*>(labelItem->widget());
            QWidget* field = fieldItem == nullptr ? nullptr : fieldItem->widget();
            const QString key = label == nullptr
                ? QString()
                : label->property("lizzieSettingsI18nKey").toString();
            if (label == nullptr || field == nullptr || (label->text() != labelText && key != i18nKey)) {
                continue;
            }
            auto* combo = qobject_cast<QComboBox*>(field);
            if (combo == nullptr) {
                combo = field->findChild<QComboBox*>();
            }
            if (combo == nullptr) {
                return false;
            }
            const int index = combo->findText(value);
            if (index < 0) {
                if (combo->isEditable()) {
                    combo->setCurrentText(value);
                    if (auto* checkBox = field->findChild<QCheckBox*>()) {
                        checkBox->setChecked(true);
                    }
                    return true;
                }
                return false;
            }
            combo->setCurrentIndex(index);
            if (auto* checkBox = field->findChild<QCheckBox*>()) {
                checkBox->setChecked(true);
            }
            return true;
        }
    }
    return false;
}

