int mainLineMoveCount(QTreeWidget* tree)
{
    if (tree == nullptr || tree->topLevelItemCount() == 0) {
        return 0;
    }
    int count = 0;
    QTreeWidgetItem* item = tree->topLevelItem(0);
    while (item != nullptr && item->childCount() > 0) {
        item = item->child(0);
        ++count;
    }
    return count;
}

QPointF analysisGraphPointPosition(const QWidget& graph, int moveNumber, double winrate, int maxMove)
{
    const QRectF plot = QRectF(graph.rect()).adjusted(16.0, 12.0, -16.0, -16.0);
    return QPointF(
        plot.left() + plot.width() * (static_cast<double>(moveNumber) / maxMove),
        plot.bottom() - plot.height() * winrate);
}

