        require(gameInfoAction != nullptr, "main window should expose Game Info action");
        QEventLoop gameInfoLoop;
        bool editedGameInfo = false;
        QTimer gameInfoDialogEditor;
        gameInfoDialogEditor.setInterval(10);
        QObject::connect(&gameInfoDialogEditor, &QTimer::timeout, [&] {
            for (QWidget* widget : QApplication::topLevelWidgets()) {
                auto* dialog = qobject_cast<QDialog*>(widget);
                if (dialog == nullptr || dialog->windowTitle() != "Game Info") {
                    continue;
                }
                auto* form = dialog->findChild<QFormLayout*>();
                if (form == nullptr) {
                    continue;
                }
                for (int row = 0; row < form->rowCount(); ++row) {
                    QLayoutItem* labelItem = form->itemAt(row, QFormLayout::LabelRole);
                    QLayoutItem* fieldItem = form->itemAt(row, QFormLayout::FieldRole);
                    auto* label = labelItem == nullptr ? nullptr : qobject_cast<QLabel*>(labelItem->widget());
                    QWidget* field = fieldItem == nullptr ? nullptr : fieldItem->widget();
                    if (label == nullptr || field == nullptr) {
                        continue;
                    }
                    const QString key = label->text();
                    auto* edit = qobject_cast<QLineEdit*>(field);
                    if (edit == nullptr) {
                        edit = field->findChild<QLineEdit*>();
                    }
                    auto* combo = qobject_cast<QComboBox*>(field);
                    if (combo == nullptr) {
                        combo = field->findChild<QComboBox*>();
                    }
                    auto* doubleSpin = qobject_cast<QDoubleSpinBox*>(field);
                    if (doubleSpin == nullptr) {
                        doubleSpin = field->findChild<QDoubleSpinBox*>();
                    }
                    auto* spin = qobject_cast<QSpinBox*>(field);
                    if (spin == nullptr) {
                        spin = field->findChild<QSpinBox*>();
                    }
                    if (key == "Rules" && combo != nullptr) {
                        combo->setCurrentText("Japanese");
                        if (auto* checkBox = field->findChild<QCheckBox*>()) {
                            checkBox->setChecked(true);
                        }
                    } else if (key == "Komi" && doubleSpin != nullptr) {
                        doubleSpin->setValue(6.5);
                        if (auto* checkBox = field->findChild<QCheckBox*>()) {
                            checkBox->setChecked(true);
                        }
                    } else if (key == "Handicap" && spin != nullptr) {
                        spin->setValue(2);
                    } else if (edit != nullptr) {
                        if (key == "Black") {
                            edit->setText("UI Black");
                        } else if (key == "White") {
                            edit->setText("UI White");
                        } else if (key == "Black Rank") {
                            edit->setText("5d");
                        } else if (key == "White Rank") {
                            edit->setText("3k");
                        } else if (key == "Result") {
                            edit->setText("W+2.5");
                        } else if (key == "Date") {
                            edit->setText("2026-06-29");
                        } else if (key == "Source") {
                            edit->setText("ui-smoke");
                        }
                    }
                }
                editedGameInfo = true;
                gameInfoDialogEditor.stop();
                dialog->accept();
                QTimer::singleShot(0, &gameInfoLoop, &QEventLoop::quit);
                return;
            }
        });
        gameInfoDialogEditor.start();
        gameInfoAction->trigger();
        execLoopWithTimeout(gameInfoLoop, 1000);
        require(editedGameInfo, "Game Info dialog should be editable from the UI");

