        require(savedExplicitDefaultsText.contains("RU[Japanese]"), "explicit Game Info rules should be saved");
        require(savedExplicitDefaultsText.contains("KM[6.5]"), "explicit Game Info komi should be saved");

        const QString clearInfoSgfPath = configHome + "/clear-game-info.sgf";
