        navigationSgf.write("(;GM[1]FF[4]SZ[9];B[dd];W[ee])");
        navigationSgf.close();
        settings.setValue("startup/firstRunComplete", true);
        settings.setValue("session/lastFile", navigationSgfPath);
        settings.setValue("session/currentNodeId", 3);
        settings.setValue("engine/executable", QString::fromLocal8Bit(argv[1]));
        settings.setValue("engine/model", "fake-model.bin.gz");
        settings.setValue("engine/gtpConfig", "fake-gtp.cfg");
        settings.setValue("compare/executable", QString::fromLocal8Bit(argv[1]));
        settings.setValue("compare/model", "fake-compare-model.bin.gz");
        settings.setValue("compare/gtpConfig", "fake-compare-gtp.cfg");
        settings.sync();

        lizzie::ui::MainWindow navigationWindow;
        navigationWindow.show();
        app.processEvents(QEventLoop::AllEvents, 100);
        QTreeWidget* navigationTree = navigationWindow.findChild<QTreeWidget*>();
        QAction* navigationAnalyzeAction = findActionByText(navigationWindow, "Analyze");
        QAction* navigationCompareAction = findActionByText(navigationWindow, "Compare");
        QAction* previousAction = findActionByText(navigationWindow, "Previous");
        QAction* nextAction = findActionByText(navigationWindow, "Next");
        QAction* undoAction = findActionByText(navigationWindow, "Undo");
        QAction* passAction = findActionByText(navigationWindow, "Pass");
        QAction* resignAction = findActionByText(navigationWindow, "Resign");
        QAction* navigationSaveAction = findActionByText(navigationWindow, "Save");
