            branchTree->findItems("3", Qt::MatchExactly | Qt::MatchRecursive, 1);
        require(!oldMainItems.empty(), "branch edit test should find demoted variation node");
        branchTree->setCurrentItem(oldMainItems.front());
        app.processEvents(QEventLoop::AllEvents, 100);

        QEventLoop branchAnalysisLoop;
        QTimer branchAnalysisPoll;
        branchAnalysisPoll.setInterval(20);
        QObject::connect(&branchAnalysisPoll, &QTimer::timeout, [&] {
            const QString text = branchOutput->toPlainText();
            if (branchAnalyzeAction->isChecked() &&
                branchCompareAction->isChecked() &&
                containsNumberedGtpCommand(text, "play B D6") &&
                containsNumberedGtpCommand(text, "play W E5") &&
                containsNumberedGtpCommand(text, "kata-analyze B") &&
                containsNumberedGtpCommand(text, "play B D6", "[compare]") &&
                containsNumberedGtpCommand(text, "play W E5", "[compare]") &&
                containsNumberedGtpCommand(text, "kata-analyze B", "[compare]")) {
                branchAnalysisPoll.stop();
                QTimer::singleShot(0, &branchAnalysisLoop, &QEventLoop::quit);
            }
        });
        branchAnalysisPoll.start();
        if (!branchAnalyzeAction->isChecked()) {
            branchAnalyzeAction->trigger();
        }
        if (!branchCompareAction->isChecked()) {
            branchCompareAction->trigger();
        }
        execLoopWithTimeout(branchAnalysisLoop, 5000);
        const QString initialBranchAnalysisText = branchOutput->toPlainText();
        const int initialBranchMainStopCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "kata-stop");
        const int initialBranchCompareStopCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "kata-stop", "[compare]");
        const int initialBranchMainAnalyzeWhiteCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "kata-analyze W");
        const int initialBranchCompareAnalyzeWhiteCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "kata-analyze W", "[compare]");
        const int initialBranchMainBlackPlayCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "play B D6");
        const int initialBranchCompareBlackPlayCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "play B D6", "[compare]");
        const int initialBranchMainDeletedPlayCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "play W E5");
        const int initialBranchCompareDeletedPlayCount =
            countNumberedGtpCommands(initialBranchAnalysisText, "play W E5", "[compare]");

        QEventLoop deleteBranchLoop;
        bool acceptedDeleteBranch = false;
        QTimer deleteBranchDialogInspector;
        deleteBranchDialogInspector.setInterval(10);
        QObject::connect(&deleteBranchDialogInspector, &QTimer::timeout, [&] {
            for (QWidget* widget : QApplication::topLevelWidgets()) {
                auto* messageBox = qobject_cast<QMessageBox*>(widget);
                if (messageBox == nullptr || messageBox->windowTitle() != "Delete Branch") {
                    continue;
                }
                auto* yesButton = messageBox->button(QMessageBox::Yes);
                if (yesButton == nullptr) {
                    continue;
                }
                acceptedDeleteBranch = true;
                deleteBranchDialogInspector.stop();
                yesButton->click();
                QTimer::singleShot(0, &deleteBranchLoop, &QEventLoop::quit);
                return;
            }
        });
        deleteBranchDialogInspector.start();
        deleteBranchAction->trigger();
        execLoopWithTimeout(deleteBranchLoop, 1000);
        require(acceptedDeleteBranch, "branch delete test should accept the delete confirmation");
        QEventLoop deleteBranchResyncLoop;
        QTimer deleteBranchResyncPoll;
        deleteBranchResyncPoll.setInterval(20);
        QObject::connect(&deleteBranchResyncPoll, &QTimer::timeout, [&] {
            const QString text = branchOutput->toPlainText();
            if (branchTree->currentItem() != nullptr &&
                branchTree->currentItem()->text(1) == "2" &&
                countNumberedGtpCommands(text, "kata-stop") > initialBranchMainStopCount &&
                countNumberedGtpCommands(text, "kata-stop", "[compare]") >
                    initialBranchCompareStopCount &&
                countNumberedGtpCommands(text, "play B D6") > initialBranchMainBlackPlayCount &&
                countNumberedGtpCommands(text, "play B D6", "[compare]") >
                    initialBranchCompareBlackPlayCount &&
                countNumberedGtpCommands(text, "play W E5") == initialBranchMainDeletedPlayCount &&
                countNumberedGtpCommands(text, "play W E5", "[compare]") ==
                    initialBranchCompareDeletedPlayCount &&
                countNumberedGtpCommands(text, "kata-analyze W") >
                    initialBranchMainAnalyzeWhiteCount &&
                countNumberedGtpCommands(text, "kata-analyze W", "[compare]") >
                    initialBranchCompareAnalyzeWhiteCount) {
                deleteBranchResyncPoll.stop();
                QTimer::singleShot(0, &deleteBranchResyncLoop, &QEventLoop::quit);
            }
        });
        deleteBranchResyncPoll.start();
        execLoopWithTimeout(deleteBranchResyncLoop, 5000);
