                bool foundTranslatedRules = false;
                bool foundCanonicalJapaneseData = false;
                for (QComboBox* combo : dialog->findChildren<QComboBox*>()) {
                    for (int index = 0; index < combo->count(); ++index) {
                        foundTranslatedRules = foundTranslatedRules ||
                            (combo->itemText(index) == QString::fromUtf8("中国规则"));
                        foundCanonicalJapaneseData = foundCanonicalJapaneseData ||
                            (combo->itemText(index) == QString::fromUtf8("日本规则") &&
                             combo->itemData(index).toString() == "Japanese");
                    }
                }
                auto* buttons = dialog->findChild<QDialogButtonBox*>();
                auto* okButton = buttons == nullptr ? nullptr : buttons->button(QDialogButtonBox::Ok);
                auto* cancelButton = buttons == nullptr ? nullptr : buttons->button(QDialogButtonBox::Cancel);
                const bool foundTranslatedStandardButtons =
                    okButton != nullptr && okButton->text() == QString::fromUtf8("确定") &&
                    cancelButton != nullptr && cancelButton->text() == QString::fromUtf8("取消");
                inspectedZhNewGameDialog = foundBoardLimits &&
                    foundTranslatedRules && foundCanonicalJapaneseData && foundTranslatedStandardButtons;
