            QAction* aiMoveAction = findActionByText(aiMoveWindow, "AI Move");
            QAction* aiMoveSaveAction = findActionByText(aiMoveWindow, "Save");
            QTreeWidget* aiMoveTree = aiMoveWindow.findChild<QTreeWidget*>();
            QPlainTextEdit* aiMoveOutput = findConsoleOutput(aiMoveWindow, "GTP Console");
            require(aiMoveAnalyzeAction != nullptr, "AI Move test should find Analyze action");
            require(aiMoveAction != nullptr, "AI Move test should find AI Move action");
            require(aiMoveSaveAction != nullptr, "AI Move test should find Save action");
            require(aiMoveTree != nullptr, "AI Move test should find game tree");
            require(aiMoveOutput != nullptr, "AI Move test should find GTP console");
            require(aiMoveTree->topLevelItemCount() == 1, "AI Move test should start with one root node");

            QEventLoop aiMoveAnalyzeLoop;
            QTimer aiMoveAnalyzePoll;
            aiMoveAnalyzePoll.setInterval(20);
            QObject::connect(&aiMoveAnalyzePoll, &QTimer::timeout, [&] {
                if (aiMoveAnalyzeAction->isChecked() &&
                    containsNumberedGtpCommand(aiMoveOutput->toPlainText(), "kata-analyze B")) {
                    aiMoveAnalyzePoll.stop();
                    QTimer::singleShot(0, &aiMoveAnalyzeLoop, &QEventLoop::quit);
                }
            });
            aiMoveAnalyzePoll.start();
            aiMoveAnalyzeAction->trigger();
            execLoopWithTimeout(aiMoveAnalyzeLoop, 5000);
            const QString aiMoveAnalyzeText = aiMoveOutput->toPlainText();
            require(
                aiMoveAnalyzeAction->isChecked() &&
                    containsNumberedGtpCommand(aiMoveAnalyzeText, "kata-analyze B"),
                "AI Move test should start realtime Analyze before requesting a generated move");
            const int aiMoveInitialStopCount = countNumberedGtpCommands(aiMoveAnalyzeText, "kata-stop");

            QEventLoop aiMoveLoop;
            QTimer aiMovePoll;
            aiMovePoll.setInterval(20);
            QObject::connect(&aiMovePoll, &QTimer::timeout, [&] {
                QTreeWidgetItem* root = aiMoveTree->topLevelItem(0);
                if (root != nullptr && root->childCount() == 1 && aiMoveTree->currentItem() != nullptr &&
                    aiMoveTree->currentItem()->text(1) != "1") {
                    aiMovePoll.stop();
                    QTimer::singleShot(0, &aiMoveLoop, &QEventLoop::quit);
                }
            });
            aiMovePoll.start();
