            const QString aiMoveProtocolText = aiMoveOutput->toPlainText();
            const qsizetype aiMoveGenMoveIndex = numberedGtpCommandIndex(aiMoveProtocolText, "genmove B");
            const qsizetype aiMoveStopBeforeGenMoveIndex =
                nthNumberedGtpCommandIndex(aiMoveProtocolText, "kata-stop", aiMoveInitialStopCount + 1);
            require(aiMoveGenMoveIndex >= 0, "AI Move should send genmove for black");
            require(!aiMoveAnalyzeAction->isChecked(), "AI Move should stop realtime Analyze");
            require(
                countNumberedGtpCommands(aiMoveProtocolText, "kata-stop") > aiMoveInitialStopCount,
                "AI Move should send kata-stop for the running realtime analysis");
            require(
                aiMoveStopBeforeGenMoveIndex >= 0 && aiMoveStopBeforeGenMoveIndex < aiMoveGenMoveIndex,
                "AI Move should stop realtime Analyze before sending genmove");
            require(
                countNumberedGtpCommands(aiMoveProtocolText, "play") == 0,
                "AI Move should not replay genmove output with a duplicate GTP play command");
