            const int selfPlayCompareInitialAnalyzeWhiteCount =
                countNumberedGtpCommands(selfPlayCompareInitialText, "kata-analyze W", "[compare]");

            QEventLoop selfPlayCompareLoop;
            QTimer selfPlayComparePoll;
