                countOccurrences(zhRealtimeExitEngineLog->toPlainText(), QString::fromUtf8("主引擎: KataGo 已退出"));
            QEventLoop zhRealtimeExitNoRestartLoop;
            QTimer::singleShot(500, &zhRealtimeExitNoRestartLoop, &QEventLoop::quit);
            execLoopWithTimeout(zhRealtimeExitNoRestartLoop, 1000);
            require(
                countOccurrences(zhRealtimeExitEngineLog->toPlainText(), QString::fromUtf8("主引擎: CUDA fake backend ready")) ==
                    zhRealtimeExitStarts,
                "Chinese realtime analysis should not auto-restart KataGo after a clean exit");
            QEventLoop zhRealtimeExitManualRestartLoop;
            QTimer zhRealtimeExitManualRestartPoll;
            zhRealtimeExitManualRestartPoll.setInterval(20);
            QObject::connect(&zhRealtimeExitManualRestartPoll, &QTimer::timeout, [&] {
                const QString text = zhRealtimeExitEngineLog->toPlainText();
                if (countOccurrences(text, QString::fromUtf8("主引擎: CUDA fake backend ready")) >
                        zhRealtimeExitStarts &&
                    countOccurrences(text, QString::fromUtf8("主引擎: KataGo 已退出")) >
                        zhRealtimeExitMessages) {
                    zhRealtimeExitManualRestartPoll.stop();
                    QTimer::singleShot(0, &zhRealtimeExitManualRestartLoop, &QEventLoop::quit);
                }
            });
            zhRealtimeExitManualRestartPoll.start();
            zhRealtimeExitRestartAction->trigger();
            execLoopWithTimeout(zhRealtimeExitManualRestartLoop, 5000);
            require(
                countOccurrences(zhRealtimeExitEngineLog->toPlainText(), QString::fromUtf8("主引擎: CUDA fake backend ready")) >
                    zhRealtimeExitStarts,
                "Chinese Restart should manually restart realtime KataGo after a clean exit");
            zhRealtimeExitWindow.close();
            settleEvents();

            settings.clear();
            const QString realtimeRestartRecoverySgfPath = configHome + "/realtime-restart-recovery.sgf";
            QFile realtimeRestartRecoverySgf(realtimeRestartRecoverySgfPath);
            require(
                realtimeRestartRecoverySgf.open(QIODevice::WriteOnly | QIODevice::Text),
                "realtime restart recovery SGF fixture should open for writing");
            realtimeRestartRecoverySgf.write("(;GM[1]FF[4]SZ[9])");
            realtimeRestartRecoverySgf.close();

            settings.setValue("startup/firstRunComplete", true);
            settings.setValue("session/lastFile", realtimeRestartRecoverySgfPath);
            settings.setValue("session/currentNodeId", 1);
            settings.setValue("engine/executable", QString::fromLocal8Bit(argv[1]));
            settings.setValue("engine/model", "fake-model.bin.gz");
            settings.setValue("engine/gtpConfig", "fake-gtp.cfg");
            settings.setValue("engine/extraArgs", "--exit-after-list-commands");
            settings.sync();

            lizzie::ui::MainWindow realtimeRestartRecoveryWindow;
            realtimeRestartRecoveryWindow.show();
            app.processEvents(QEventLoop::AllEvents, 100);
            QAction* realtimeRestartRecoveryAnalyzeAction =
                findActionByText(realtimeRestartRecoveryWindow, "Analyze");
            QAction* realtimeRestartRecoverySettingsAction =
                findActionByText(realtimeRestartRecoveryWindow, "Settings");
            QAction* realtimeRestartRecoveryRestartAction =
                findActionByText(realtimeRestartRecoveryWindow, "Restart");
            QStatusBar* realtimeRestartRecoveryStatus = realtimeRestartRecoveryWindow.statusBar();
            QPlainTextEdit* realtimeRestartRecoveryOutput =
                findConsoleOutput(realtimeRestartRecoveryWindow, "GTP Console");
            QPlainTextEdit* realtimeRestartRecoveryEngineLog =
                findConsoleOutput(realtimeRestartRecoveryWindow, "Engine Log");
            require(
                realtimeRestartRecoveryAnalyzeAction != nullptr,
                "realtime restart recovery test should find Analyze action");
            require(
                realtimeRestartRecoverySettingsAction != nullptr,
                "realtime restart recovery test should find Settings action");
            require(
                realtimeRestartRecoveryRestartAction != nullptr,
                "realtime restart recovery test should find Restart action");
            require(
                realtimeRestartRecoveryStatus != nullptr,
                "realtime restart recovery test should find status bar");
            require(
                realtimeRestartRecoveryOutput != nullptr,
                "realtime restart recovery test should find GTP console");
            require(
                realtimeRestartRecoveryEngineLog != nullptr,
                "realtime restart recovery test should find engine log");

            QEventLoop realtimeRestartRecoveryExitLoop;
            QTimer realtimeRestartRecoveryExitPoll;
            realtimeRestartRecoveryExitPoll.setInterval(20);
            QObject::connect(&realtimeRestartRecoveryExitPoll, &QTimer::timeout, [&] {
                if (!realtimeRestartRecoveryAnalyzeAction->isChecked() &&
                    realtimeRestartRecoveryStatus->currentMessage().contains("KataGo exited") &&
                    realtimeRestartRecoveryEngineLog->toPlainText().contains("main: KataGo exited")) {
                    realtimeRestartRecoveryExitPoll.stop();
                    QTimer::singleShot(0, &realtimeRestartRecoveryExitLoop, &QEventLoop::quit);
                }
            });
            realtimeRestartRecoveryExitPoll.start();
            realtimeRestartRecoveryAnalyzeAction->trigger();
            execLoopWithTimeout(realtimeRestartRecoveryExitLoop, 5000);
            require(
                !realtimeRestartRecoveryAnalyzeAction->isChecked(),
                "realtime restart recovery should stop Analyze after the failing engine exits");
            require(
                countNumberedGtpCommands(realtimeRestartRecoveryOutput->toPlainText(), "kata-analyze B") == 0,
                "failing realtime restart recovery engine should exit before kata-analyze");
            const int realtimeRestartRecoveryFailedStarts =
                countOccurrences(realtimeRestartRecoveryEngineLog->toPlainText(), "main: CUDA fake backend ready");
            const int realtimeRestartRecoveryFailedExits =
                countOccurrences(realtimeRestartRecoveryEngineLog->toPlainText(), "main: KataGo exited");

            bool acceptedRealtimeRestartRecoverySettings = false;
            QEventLoop realtimeRestartRecoverySettingsLoop;
            QTimer realtimeRestartRecoverySettingsEditor;
            realtimeRestartRecoverySettingsEditor.setInterval(10);
            QObject::connect(&realtimeRestartRecoverySettingsEditor, &QTimer::timeout, [&] {
                for (QWidget* widget : QApplication::topLevelWidgets()) {
                    auto* dialog = qobject_cast<QDialog*>(widget);
                    if (dialog == nullptr || dialog->windowTitle() != "Settings") {
                        continue;
                    }
                    if (!setFormLineEdit(dialog, "extraArgs", "")) {
                        continue;
                    }
                    auto* buttons = dialog->findChild<QDialogButtonBox*>();
                    auto* okButton = buttons == nullptr ? nullptr : buttons->button(QDialogButtonBox::Ok);
                    if (okButton == nullptr) {
                        continue;
                    }
                    acceptedRealtimeRestartRecoverySettings = true;
                    realtimeRestartRecoverySettingsEditor.stop();
                    okButton->click();
                    QTimer::singleShot(0, &realtimeRestartRecoverySettingsLoop, &QEventLoop::quit);
                    return;
                }
            });
            realtimeRestartRecoverySettingsEditor.start();
            realtimeRestartRecoverySettingsAction->trigger();
            execLoopWithTimeout(realtimeRestartRecoverySettingsLoop, 5000, [&] {
                rejectTopLevelDialogs();
            });
            require(
                acceptedRealtimeRestartRecoverySettings,
                "realtime restart recovery should accept cleared engine args");
            settings.sync();
            require(
                settings.value("engine/extraArgs").toString().isEmpty(),
                "realtime restart recovery should persist cleared engine args");

            QEventLoop realtimeRestartRecoveryStartLoop;
            QTimer realtimeRestartRecoveryStartPoll;
            realtimeRestartRecoveryStartPoll.setInterval(20);
            QObject::connect(&realtimeRestartRecoveryStartPoll, &QTimer::timeout, [&] {
                const QString log = realtimeRestartRecoveryEngineLog->toPlainText();
                const QString console = realtimeRestartRecoveryOutput->toPlainText();
                if (countOccurrences(log, "main: CUDA fake backend ready") > realtimeRestartRecoveryFailedStarts &&
                    countOccurrences(log, "main: KataGo exited") == realtimeRestartRecoveryFailedExits &&
                    console.contains("engine capabilities: kata-analyze=yes")) {
                    realtimeRestartRecoveryStartPoll.stop();
                    QTimer::singleShot(0, &realtimeRestartRecoveryStartLoop, &QEventLoop::quit);
                }
            });
            realtimeRestartRecoveryStartPoll.start();
            realtimeRestartRecoveryRestartAction->trigger();
            execLoopWithTimeout(realtimeRestartRecoveryStartLoop, 5000);
            const int realtimeRestartRecoveryHealthyStarts =
                countOccurrences(realtimeRestartRecoveryEngineLog->toPlainText(), "main: CUDA fake backend ready");
            require(
                realtimeRestartRecoveryHealthyStarts > realtimeRestartRecoveryFailedStarts,
                "Restart should start a healthy main engine after clearing failing args");
            require(
                countOccurrences(realtimeRestartRecoveryEngineLog->toPlainText(), "main: KataGo exited") ==
                    realtimeRestartRecoveryFailedExits,
                "healthy restart should not immediately exit again");

            const int realtimeRestartRecoveryAnalyzeBefore =
                countNumberedGtpCommands(realtimeRestartRecoveryOutput->toPlainText(), "kata-analyze B");
            QEventLoop realtimeRestartRecoveryAnalyzeLoop;
            QTimer realtimeRestartRecoveryAnalyzePoll;
            realtimeRestartRecoveryAnalyzePoll.setInterval(20);
            QObject::connect(&realtimeRestartRecoveryAnalyzePoll, &QTimer::timeout, [&] {
                if (realtimeRestartRecoveryAnalyzeAction->isChecked() &&
                    countOccurrences(realtimeRestartRecoveryEngineLog->toPlainText(), "main: CUDA fake backend ready") ==
                        realtimeRestartRecoveryHealthyStarts &&
                    countNumberedGtpCommands(realtimeRestartRecoveryOutput->toPlainText(), "kata-analyze B") >
                        realtimeRestartRecoveryAnalyzeBefore) {
                    realtimeRestartRecoveryAnalyzePoll.stop();
                    QTimer::singleShot(0, &realtimeRestartRecoveryAnalyzeLoop, &QEventLoop::quit);
                }
            });
            realtimeRestartRecoveryAnalyzePoll.start();
            realtimeRestartRecoveryAnalyzeAction->trigger();
            execLoopWithTimeout(realtimeRestartRecoveryAnalyzeLoop, 5000);
            require(
                realtimeRestartRecoveryAnalyzeAction->isChecked(),
                "Analyze should start after manual Restart recovers the main engine");
            require(
                countOccurrences(realtimeRestartRecoveryEngineLog->toPlainText(), "main: CUDA fake backend ready") ==
                    realtimeRestartRecoveryHealthyStarts,
                "Analyze after Restart should reuse the healthy restarted engine");
            realtimeRestartRecoveryWindow.close();
            settleEvents();

            settings.clear();
            const QString realtimeClearSgfPath = configHome + "/realtime-clear-stale-analysis.sgf";
            QFile realtimeClearSgf(realtimeClearSgfPath);
            require(
                realtimeClearSgf.open(QIODevice::WriteOnly | QIODevice::Text),
                "realtime clear stale SGF fixture should open for writing");
            realtimeClearSgf.write(
                "(;GM[1]FF[4]SZ[9]C[user note\n\nLizzieYzy analysis\nWinrate: 47.0%\nScoreMean: -1.50\nVisits: 12]"
                "LZOP[old-root-analysis]LZYPERSP[W])");
            realtimeClearSgf.close();

            settings.setValue("startup/firstRunComplete", true);
            settings.setValue("session/lastFile", realtimeClearSgfPath);
            settings.setValue("session/currentNodeId", 1);
            settings.setValue("engine/executable", QString::fromLocal8Bit(argv[1]));
            settings.setValue("engine/model", "fake-model.bin.gz");
            settings.setValue("engine/gtpConfig", "fake-gtp.cfg");
            settings.setValue("engine/extraArgs", "--exit-after-kata-stop");
            settings.sync();

            lizzie::ui::MainWindow realtimeClearWindow;
            realtimeClearWindow.show();
            app.processEvents(QEventLoop::AllEvents, 100);
            QAction* realtimeClearAnalyzeAction = findActionByText(realtimeClearWindow, "Analyze");
            QAction* realtimeClearSaveAction = findActionByText(realtimeClearWindow, "Save");
            QStatusBar* realtimeClearStatus = realtimeClearWindow.statusBar();
            require(realtimeClearAnalyzeAction != nullptr, "realtime clear test should find Analyze action");
            require(realtimeClearSaveAction != nullptr, "realtime clear test should find Save action");
            require(realtimeClearStatus != nullptr, "realtime clear test should find status bar");

            QEventLoop realtimeClearLoop;
            QTimer realtimeClearPoll;
            realtimeClearPoll.setInterval(20);
            QObject::connect(&realtimeClearPoll, &QTimer::timeout, [&] {
                if (!realtimeClearAnalyzeAction->isChecked() &&
                    realtimeClearStatus->currentMessage().contains("KataGo exited")) {
                    realtimeClearPoll.stop();
                    QTimer::singleShot(0, &realtimeClearLoop, &QEventLoop::quit);
                }
            });
            realtimeClearPoll.start();
            realtimeClearAnalyzeAction->trigger();
            execLoopWithTimeout(realtimeClearLoop, 5000);
            realtimeClearSaveAction->trigger();
            QFile savedRealtimeClearSgf(realtimeClearSgfPath);
            require(
                savedRealtimeClearSgf.open(QIODevice::ReadOnly | QIODevice::Text),
                "realtime clear saved SGF should reopen");
            const QString savedRealtimeClearText = QString::fromUtf8(savedRealtimeClearSgf.readAll());
            require(savedRealtimeClearText.contains("C[user note]"), "realtime clear should preserve user comments");
            require(
                !savedRealtimeClearText.contains("old-root-analysis"),
                "realtime clear should remove stale root LZOP before a new analysis update");
            require(
                !savedRealtimeClearText.contains("LZYPERSP["),
                "realtime clear should remove stale analysis perspective before a new analysis update");
            require(
                !savedRealtimeClearText.contains("LizzieYzy analysis"),
                "realtime clear should remove stale generated analysis comments before a new analysis update");
            realtimeClearWindow.close();
            settleEvents();

            settings.clear();
            const QString rectangularRealtimeSgfPath = configHome + "/rectangular-realtime-sync.sgf";
            QFile rectangularRealtimeSgf(rectangularRealtimeSgfPath);
            require(
                rectangularRealtimeSgf.open(QIODevice::WriteOnly | QIODevice::Text),
                "rectangular realtime SGF fixture should open for writing");
            rectangularRealtimeSgf.write("(;GM[1]FF[4]SZ[9:13]KM[6.5])");
            rectangularRealtimeSgf.close();

            settings.setValue("startup/firstRunComplete", true);
            settings.setValue("session/lastFile", rectangularRealtimeSgfPath);
            settings.setValue("session/currentNodeId", 1);
            settings.setValue("engine/executable", QString::fromLocal8Bit(argv[1]));
            settings.setValue("engine/model", "fake-model.bin.gz");
            settings.setValue("engine/gtpConfig", "fake-gtp.cfg");
            settings.sync();

            lizzie::ui::MainWindow rectangularRealtimeWindow;
            rectangularRealtimeWindow.show();
            app.processEvents(QEventLoop::AllEvents, 100);
            QAction* rectangularRealtimeAnalyzeAction = findActionByText(rectangularRealtimeWindow, "Analyze");
            QPlainTextEdit* rectangularRealtimeOutput =
                findConsoleOutput(rectangularRealtimeWindow, "GTP Console");
            require(
                rectangularRealtimeAnalyzeAction != nullptr,
                "rectangular realtime test should find Analyze action");
            require(
                rectangularRealtimeOutput != nullptr,
                "rectangular realtime test should find GTP console output");

            QEventLoop rectangularRealtimeLoop;
            QTimer rectangularRealtimePoll;
            rectangularRealtimePoll.setInterval(20);
            QObject::connect(&rectangularRealtimePoll, &QTimer::timeout, [&] {
                const QString text = rectangularRealtimeOutput->toPlainText();
                const qsizetype clearIndex = numberedGtpCommandIndex(text, "clear_board");
                const qsizetype rectangularIndex =
                    numberedGtpCommandIndex(text, "rectangular_boardsize 9 13");
                const qsizetype komiIndex = numberedGtpCommandIndex(text, "komi 6.5");
                const qsizetype analyzeIndex = numberedGtpCommandIndex(text, "kata-analyze B");
                if (clearIndex >= 0 && rectangularIndex > clearIndex && komiIndex > rectangularIndex &&
                    analyzeIndex > komiIndex) {
                    rectangularRealtimePoll.stop();
                    QTimer::singleShot(0, &rectangularRealtimeLoop, &QEventLoop::quit);
                }
            });
            rectangularRealtimePoll.start();
            rectangularRealtimeAnalyzeAction->trigger();
            execLoopWithTimeout(rectangularRealtimeLoop, 5000);
            const QString rectangularRealtimeText = rectangularRealtimeOutput->toPlainText();
            const qsizetype rectangularClearIndex =
                numberedGtpCommandIndex(rectangularRealtimeText, "clear_board");
            const qsizetype rectangularSizeIndex =
                numberedGtpCommandIndex(rectangularRealtimeText, "rectangular_boardsize 9 13");
            const qsizetype rectangularKomiIndex =
                numberedGtpCommandIndex(rectangularRealtimeText, "komi 6.5");
            const qsizetype rectangularAnalyzeIndex =
                numberedGtpCommandIndex(rectangularRealtimeText, "kata-analyze B");
            require(rectangularClearIndex >= 0, "rectangular realtime should clear the board before sync");
            require(
                rectangularSizeIndex > rectangularClearIndex,
                "rectangular realtime should set rectangular board size after clear_board");
            require(
                rectangularKomiIndex > rectangularSizeIndex,
                "rectangular realtime should send SGF komi after rectangular board size");
            require(
                rectangularAnalyzeIndex > rectangularKomiIndex,
                "rectangular realtime should start analysis after rectangular board sync");
            require(
                !containsNumberedGtpCommand(rectangularRealtimeText, "boardsize 9"),
                "rectangular realtime should not send a square boardsize command");
            rectangularRealtimeAnalyzeAction->trigger();
            rectangularRealtimeWindow.close();
            settleEvents();

            settings.clear();
            const QString wideRealtimeSgfPath = configHome + "/wide-realtime-sync.sgf";
            QFile wideRealtimeSgf(wideRealtimeSgfPath);
            require(
                wideRealtimeSgf.open(QIODevice::WriteOnly | QIODevice::Text),
                "wide realtime SGF fixture should open for writing");
            wideRealtimeSgf.write("(;GM[1]FF[4]SZ[26:9];B[za])");
            wideRealtimeSgf.close();

            settings.setValue("startup/firstRunComplete", true);
            settings.setValue("session/lastFile", wideRealtimeSgfPath);
            settings.setValue("session/currentNodeId", 2);
            settings.setValue("engine/executable", QString::fromLocal8Bit(argv[1]));
            settings.setValue("engine/model", "fake-model.bin.gz");
            settings.setValue("engine/gtpConfig", "fake-gtp.cfg");
            settings.sync();

            lizzie::ui::MainWindow wideRealtimeWindow;
            wideRealtimeWindow.show();
            app.processEvents(QEventLoop::AllEvents, 100);
            QAction* wideRealtimeAnalyzeAction = findActionByText(wideRealtimeWindow, "Analyze");
            QStatusBar* wideRealtimeStatus = wideRealtimeWindow.statusBar();
            QPlainTextEdit* wideRealtimeOutput = findConsoleOutput(wideRealtimeWindow, "GTP Console");
            QPlainTextEdit* wideRealtimeEngineLog = findConsoleOutput(wideRealtimeWindow, "Engine Log");
            require(wideRealtimeAnalyzeAction != nullptr, "wide realtime test should find Analyze action");
            require(wideRealtimeStatus != nullptr, "wide realtime test should find status bar");
            require(wideRealtimeOutput != nullptr, "wide realtime test should find GTP console output");
            require(wideRealtimeEngineLog != nullptr, "wide realtime test should find engine log output");

            QEventLoop wideRealtimeLoop;
            QTimer wideRealtimePoll;
            wideRealtimePoll.setInterval(20);
            QObject::connect(&wideRealtimePoll, &QTimer::timeout, [&] {
                if (!wideRealtimeAnalyzeAction->isChecked() &&
                    wideRealtimeOutput->toPlainText().contains("board width cannot be represented by GTP coordinates") &&
                    wideRealtimeEngineLog->toPlainText().contains("main: board width cannot be represented by GTP coordinates")) {
                    wideRealtimePoll.stop();
                    QTimer::singleShot(0, &wideRealtimeLoop, &QEventLoop::quit);
                }
            });
            wideRealtimePoll.start();
            wideRealtimeAnalyzeAction->trigger();
            execLoopWithTimeout(wideRealtimeLoop, 5000);
            const QString wideRealtimeText = wideRealtimeOutput->toPlainText();
            require(
                !wideRealtimeAnalyzeAction->isChecked(),
                "wide realtime board should uncheck Analyze after fatal sync warning");
            require(
                wideRealtimeText.contains("engine sync was skipped"),
                "wide realtime board should write a fatal sync diagnostic to the GTP console");
            require(
                wideRealtimeEngineLog->toPlainText().contains("main: board width cannot be represented by GTP coordinates"),
                "wide realtime board should write a fatal sync diagnostic to the engine log");
            require(
                wideRealtimeStatus->currentMessage().contains("board cannot be synced to GTP"),
                std::string("wide realtime board should update the status bar; got ") +
                    wideRealtimeStatus->currentMessage().toStdString());
            require(
                !containsNumberedGtpCommand(wideRealtimeText, "clear_board") &&
                    !containsNumberedGtpCommand(wideRealtimeText, "boardsize") &&
                    !containsNumberedGtpCommand(wideRealtimeText, "rectangular_boardsize") &&
                    !containsNumberedGtpCommand(wideRealtimeText, "play"),
                "wide realtime board should not send malformed board sync commands");
            wideRealtimeWindow.close();
            settleEvents();

            settings.clear();
            settings.setValue("startup/firstRunComplete", true);
            settings.setValue("session/lastFile", wideRealtimeSgfPath);
            settings.setValue("session/currentNodeId", 2);
            settings.setValue("compare/executable", QString::fromLocal8Bit(argv[1]));
            settings.setValue("compare/model", "fake-compare-model.bin.gz");
            settings.setValue("compare/gtpConfig", "fake-compare-gtp.cfg");
            settings.sync();

            lizzie::ui::MainWindow wideCompareWindow;
            wideCompareWindow.show();
            app.processEvents(QEventLoop::AllEvents, 100);
            QAction* wideCompareAction = findActionByText(wideCompareWindow, "Compare");
            QStatusBar* wideCompareStatus = wideCompareWindow.statusBar();
            QPlainTextEdit* wideCompareOutput = findConsoleOutput(wideCompareWindow, "GTP Console");
            QPlainTextEdit* wideCompareEngineLog = findConsoleOutput(wideCompareWindow, "Engine Log");
            require(wideCompareAction != nullptr, "wide Compare test should find Compare action");
            require(wideCompareStatus != nullptr, "wide Compare test should find status bar");
            require(wideCompareOutput != nullptr, "wide Compare test should find GTP console output");
            require(wideCompareEngineLog != nullptr, "wide Compare test should find engine log output");

            QEventLoop wideCompareLoop;
            QTimer wideComparePoll;
            wideComparePoll.setInterval(20);
            QObject::connect(&wideComparePoll, &QTimer::timeout, [&] {
                if (!wideCompareAction->isChecked() &&
                    wideCompareOutput->toPlainText().contains(
                        "system: [compare] board width cannot be represented by GTP coordinates") &&
                    wideCompareEngineLog->toPlainText().contains(
                        "compare: board width cannot be represented by GTP coordinates")) {
                    wideComparePoll.stop();
                    QTimer::singleShot(0, &wideCompareLoop, &QEventLoop::quit);
                }
            });
            wideComparePoll.start();
            wideCompareAction->trigger();
            execLoopWithTimeout(wideCompareLoop, 5000);
            const QString wideCompareText = wideCompareOutput->toPlainText();
            require(
                !wideCompareAction->isChecked(),
                "wide Compare board should uncheck Compare after fatal sync warning");
            require(
                wideCompareText.contains("system: [compare] board width cannot be represented by GTP coordinates"),
                "wide Compare board should write a prefixed fatal sync diagnostic to the GTP console");
            require(
                wideCompareEngineLog->toPlainText().contains(
                    "compare: board width cannot be represented by GTP coordinates"),
                "wide Compare board should write a fatal sync diagnostic to the engine log");
            require(
                wideCompareStatus->currentMessage().contains("Compare analysis skipped: board cannot be synced to GTP"),
                std::string("wide Compare board should update the status bar; got ") +
                    wideCompareStatus->currentMessage().toStdString());
            require(
                !containsNumberedGtpCommand(wideCompareText, "clear_board", "[compare]") &&
                    !containsNumberedGtpCommand(wideCompareText, "boardsize", "[compare]") &&
                    !containsNumberedGtpCommand(wideCompareText, "rectangular_boardsize", "[compare]") &&
                    !containsNumberedGtpCommand(wideCompareText, "play", "[compare]") &&
                    !containsNumberedGtpCommand(wideCompareText, "kata-analyze", "[compare]"),
                "wide Compare board should not send malformed compare sync or analysis commands");
            wideCompareWindow.close();
            settleEvents();

            settings.clear();
            settings.setValue("appearance/language", "zh");
            settings.setValue("startup/firstRunComplete", true);
            settings.setValue("session/lastFile", wideRealtimeSgfPath);
            settings.setValue("session/currentNodeId", 2);
            settings.setValue("compare/executable", QString::fromLocal8Bit(argv[1]));
            settings.setValue("compare/model", "fake-compare-model.bin.gz");
            settings.setValue("compare/gtpConfig", "fake-compare-gtp.cfg");
            settings.sync();

            lizzie::ui::MainWindow zhWideCompareWindow;
            zhWideCompareWindow.show();
            app.processEvents(QEventLoop::AllEvents, 100);
            QAction* zhWideCompareAction =
                findActionByText(zhWideCompareWindow, QString::fromUtf8("对比"));
            QStatusBar* zhWideCompareStatus = zhWideCompareWindow.statusBar();
            QPlainTextEdit* zhWideCompareOutput =
                findConsoleOutput(zhWideCompareWindow, QString::fromUtf8("GTP 控制台"));
            QPlainTextEdit* zhWideCompareEngineLog =
                findConsoleOutput(zhWideCompareWindow, QString::fromUtf8("引擎日志"));
            require(zhWideCompareAction != nullptr, "Chinese wide Compare test should find Compare action");
            require(zhWideCompareStatus != nullptr, "Chinese wide Compare test should find status bar");
            require(zhWideCompareOutput != nullptr, "Chinese wide Compare test should find GTP console output");
            require(zhWideCompareEngineLog != nullptr, "Chinese wide Compare test should find engine log output");

            QEventLoop zhWideCompareLoop;
            QTimer zhWideComparePoll;
            zhWideComparePoll.setInterval(20);
            QObject::connect(&zhWideComparePoll, &QTimer::timeout, [&] {
                if (!zhWideCompareAction->isChecked() &&
                    zhWideCompareOutput->toPlainText().contains(
                        QString::fromUtf8("系统: 对比：棋盘宽度无法用 GTP 坐标表示")) &&
                    zhWideCompareEngineLog->toPlainText().contains(
                        QString::fromUtf8("对比引擎: 棋盘宽度无法用 GTP 坐标表示"))) {
                    zhWideComparePoll.stop();
                    QTimer::singleShot(0, &zhWideCompareLoop, &QEventLoop::quit);
                }
            });
            zhWideComparePoll.start();
            zhWideCompareAction->trigger();
            execLoopWithTimeout(zhWideCompareLoop, 5000);
            const QString zhWideCompareText = zhWideCompareOutput->toPlainText();
            require(
                !zhWideCompareAction->isChecked(),
                "Chinese wide Compare board should uncheck Compare after fatal sync warning");
            require(
                zhWideCompareText.contains(QString::fromUtf8("系统: 对比：棋盘宽度无法用 GTP 坐标表示；已跳过引擎同步")),
                "Chinese wide Compare board should localize the fatal sync diagnostic in the GTP console");
